-- ============================================================
-- Migration 009 — Section 4 content (Adjustment Analysis)
-- M2-S4-C1 #2: s4_m1_standard — Mortgage Lending, Intermediate
--
-- Adds ONE scenario to the Mortgage Lending category, exercising
-- the three new step2 table kinds NOT touched by migration 008:
--   - paired_dollar_diff      (bathroom pair table)
--   - paired_pct_per_month    (date / market conditions pair table)
--   - cost_calc for bath      (paired with paired_dollar_diff)
-- (paired_dollar_per_unit and cost_calc for GLA were already
--  proven by s4_m1_s1 in migration 008.)
--
-- Scenario: 3124 Pembrooke Circle, Greenville SC — Standard URAR
-- underwriting with three adjustment types (GLA, Bathroom, Date).
-- Difficulty: 'intermediate' in DB; displayed as "Standard".
--
-- No schema changes. Categories and the adjustment_grid field
-- already exist from migration 008.
--
-- Idempotency: this migration runs once and is recorded in the
-- schemaversion table by the migration runner.
-- ============================================================

BEGIN;

-- ------------------------------------------------------------
-- Insert scenario
-- ------------------------------------------------------------
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 2,
  'intermediate',
  '3124 Pembrooke Circle — Standard URAR Underwriting',
  'You are appraising a home at 3124 Pembrooke Circle, Greenville SC for a purchase loan underwriting assignment with Carolina Federal Savings Bank. The contract price is $318,000. The subject is a 2,150 SF ranch built in 2007 with three bedrooms, 2.5 bathrooms, a 2-car attached garage, and is in good condition.

Your comparable selection is complete — three closed sales within the past nine months. Two are very recent; one sold nine months ago and will require a market conditions adjustment in addition to its other differences. Your task in this scenario is to identify which features differ from the subject, derive market-supported adjustment values (including a monthly appreciation rate from resale-pair data), apply them to each comparable, and reconcile the adjusted prices into a credible value indication that supports — or refutes — the contract price.'
FROM scenario_categories WHERE code = 'M2-S4-C1';

-- ------------------------------------------------------------
-- Insert model_answer
--   field_options_override = student-facing scenario data
--   model_data             = gated post-submit model values
-- ------------------------------------------------------------
INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address": "3124 Pembrooke Circle, Greenville SC 29615", "context": "Purchase Loan Underwriting · Carolina Federal Savings Bank · Contract Price $318,000", "difficulty": "Standard", "fact_sheet": [["GLA", "2,150 SF"], ["Bathrooms", "2.5"], ["Bedrooms", "3"], ["Garage", "2-car attached"], ["Year Built", "2007"], ["Condition", "Good"]]}, "comps": [{"id": "C1", "label": "Comp 1", "price": 328000, "fact_sheet": {"Sale Price": "$328,000", "Sale Date": "3 mos. ago", "GLA": "2,300 SF", "Bathrooms": "2.5", "Bedrooms": "3", "Garage": "2-car", "Year Built": "2007", "Condition": "Good"}}, {"id": "C2", "label": "Comp 2", "price": 322500, "fact_sheet": {"Sale Price": "$322,500", "Sale Date": "2 mos. ago", "GLA": "2,150 SF", "Bathrooms": "3 full", "Bedrooms": "3", "Garage": "2-car", "Year Built": "2008", "Condition": "Good"}}, {"id": "C3", "label": "Comp 3", "price": 302000, "fact_sheet": {"Sale Price": "$302,000", "Sale Date": "9 mos. ago", "GLA": "2,150 SF", "Bathrooms": "2.5", "Bedrooms": "3", "Garage": "2-car", "Year Built": "2006", "Condition": "Good"}}], "features": [{"key": "gla", "label": "GLA", "unit_label": "$/SF", "step3_kind": "per_unit", "subject_units": 2150, "comp_units": {"C1": 2300, "C2": 2150, "C3": 2150}}, {"key": "bath", "label": "Bathrooms", "unit_label": "$", "step3_kind": "lump_sum"}, {"key": "date", "label": "Market Conditions", "unit_label": "%/mo", "step3_kind": "lump_sum"}], "step1_grid": [{"label": "Sale Price", "subject": "N/A", "comp_values": {"C1": "$328,000", "C2": "$322,500", "C3": "$302,000"}, "diff_comps": []}, {"label": "Sale Date", "subject": "Current", "comp_values": {"C1": "3 mos. ago", "C2": "2 mos. ago", "C3": "9 mos. ago"}, "feature_key": "date", "diff_comps": ["C3"], "diff_directions": {"C3": "inferior"}}, {"label": "GLA", "subject": "2,150 SF", "comp_values": {"C1": "2,300 SF", "C2": "2,150 SF", "C3": "2,150 SF"}, "feature_key": "gla", "diff_comps": ["C1"], "diff_directions": {"C1": "superior"}}, {"label": "Bathrooms", "subject": "2.5", "comp_values": {"C1": "2.5", "C2": "3 full", "C3": "2.5"}, "feature_key": "bath", "diff_comps": ["C2"], "diff_directions": {"C2": "superior"}}, {"label": "Bedrooms", "subject": "3", "comp_values": {"C1": "3", "C2": "3", "C3": "3"}, "diff_comps": []}, {"label": "Garage", "subject": "2-car attached", "comp_values": {"C1": "2-car", "C2": "2-car", "C3": "2-car"}, "diff_comps": []}, {"label": "Year Built", "subject": "2007", "comp_values": {"C1": "2007", "C2": "2008", "C3": "2006"}, "diff_comps": []}, {"label": "Condition", "subject": "Good", "comp_values": {"C1": "Good", "C2": "Good", "C3": "Good"}, "diff_comps": []}], "step2": {"tabs": [{"key": "paired", "label": "Paired Sales Analysis", "intro": "Use the supporting market data to derive contributory values for each adjustment type. Complete all three paired tables — including the new Market Conditions section — then reconcile.", "tables": [{"kind": "paired_dollar_per_unit", "feature_key": "gla", "title": "GLA Pairs — Calculate $/SF", "instruction": "Each pair is confirmed equivalent except for GLA. Divide Price Difference ÷ SF Difference. Examine the spread carefully — Pair 3 diverges noticeably from Pairs 1 & 2. Bracket toward the consistent pairs and address the divergence in your reconciliation.", "input_label": "Your $/SF", "input_suffix": "/SF", "rows": [{"label": "1", "cells": ["2,000 SF / $304,000", "2,150 SF / $311,400", "150 SF", "$7,400"]}, {"label": "2", "cells": ["2,100 SF / $312,500", "2,250 SF / $320,000", "150 SF", "$7,500"]}, {"label": "3", "cells": ["2,050 SF / $308,000", "2,200 SF / $316,200", "150 SF", "$8,200"]}], "column_headers": ["Pair", "Sale A (SF / Price)", "Sale B (SF / Price)", "SF Diff", "Price Diff"], "concluded_label": "Concluded GLA Adjustment", "concluded_helper": "Weight the consistent pairs; address Pair 3''s divergence."}, {"kind": "paired_dollar_diff", "feature_key": "bath", "title": "Bathroom Pairs — Calculate Price Difference", "instruction": "Pairs isolate the 2.5 vs. 3 full bath difference. All other features confirmed equivalent. Subtract the 2.5-bath sale price from the 3-full-bath sale price.", "input_label": "Your Price Difference", "input_suffix": "", "rows": [{"label": "1", "cells": ["$308,500", "$315,500"]}, {"label": "2", "cells": ["$315,000", "$322,200"]}], "column_headers": ["Pair", "2.5 Bath Sale", "3 Full Bath Sale"], "concluded_label": "Concluded Bathroom Adjustment", "concluded_helper": "Bracket your two results."}, {"kind": "paired_pct_per_month", "feature_key": "date", "title": "Market Conditions — Resale Pair Analysis", "instruction": "The same properties sold twice. For each pair, calculate the monthly appreciation rate using: (Resale − Original) ÷ Original ÷ Months × 100", "input_label": "Your %/Month", "input_suffix": "%/mo", "rows": [{"label": "A", "cells": ["$298,000", "$308,130", "9"]}, {"label": "B", "cells": ["$314,000", "$324,374", "11"]}, {"label": "C", "cells": ["$305,000", "$312,520", "7"]}], "column_headers": ["Property", "Original Sale Price", "Resale Price", "Months"], "concluded_label": "Concluded Monthly Rate", "concluded_helper": "Average or bracket your three results."}]}, {"key": "cost", "label": "Cost-Based Support", "intro": "Calculate the depreciated contributory value for GLA and Bathrooms. No cost method is applicable for market conditions — your paired sales conclusion is the only support.", "items": [{"kind": "cost_calc", "feature_key": "gla", "title": "GLA Contributory Value ($/SF)", "fact_rows": [["RCN", "$80.00 / SF"], ["Effective Age", "17 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "17 ÷ 60 = 28.3%"], ["Formula", "$80.00 × (1 − 0.283) = ?"]], "input_suffix": "/SF"}, {"kind": "cost_calc", "feature_key": "bath", "title": "Bathroom Cost (Full Bath Addition)", "fact_rows": [["Cost to Add Full Bath", "$14,000"], ["Effective Age", "17 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "28.3%"], ["Formula", "$14,000 × (1 − 0.283) = ?"]], "input_suffix": ""}]}], "reconciliation": {"instruction": "Review both method indications and enter your reconciled adjustment for each item. Cost typically functions as a ceiling — weight paired sales when the two methods diverge. For market conditions, your paired sales conclusion is the only support; cost is not applicable.", "items": [{"feature_key": "gla", "label": "GLA Adjustment ($/SF)"}, {"feature_key": "bath", "label": "Bathroom Adjustment ($)"}, {"feature_key": "date", "label": "Market Conditions Adjustment (%/mo)"}]}}, "step3": {"instruction": "Apply your reconciled adjustments to each comparable. Use a NEGATIVE value where the comp is superior to the subject, and a POSITIVE value where it is inferior. For Comp 3 (market conditions), calculate the dollar amount as: $302,000 × 9 months × your reconciled %/mo ÷ 100. Then document your support methodology and rationale for each adjustment.", "applicable": {"C1": ["gla"], "C2": ["bath"], "C3": ["date"]}, "method_dropdown": ["Paired Sales Analysis", "Grouped Paired Sales", "Cost-Based Support", "Market Conditions (Resale Pairs)", "Income Differential / GRM", "Regression Analysis", "Appraiser Judgment / Extraction"], "support_min_chars": 15}, "step4": {"show_net_gross_panel": false}}'::jsonb,
  '{"step1_correct_flags": {"C1": ["gla"], "C2": ["bath"], "C3": ["date"]}, "step1_rationale": "Comp 1 differs from the subject in GLA only (150 SF larger). Comp 2 differs in bathroom count only (3 full vs. the subject''s 2.5). Comp 3 sold 9 months ago in an appreciating market and requires a market conditions adjustment; it matches the subject in all physical features. All other features (bedrooms, garage, year built, and condition) are equivalent across all three comparables and require no adjustment.", "step2_tables": {"paired": {"gla": {"pair_answers": [49.33, 50.00, 54.67], "concluded_range": [49.0, 53.0], "rationale": "Pairs 1 and 2 cluster tightly at $49.33 and $50.00/SF — strong, consistent market evidence. Pair 3 diverges to $54.67/SF and should be addressed in the rationale (possibly a different submarket or anomalous sale) but not allowed to dominate the conclusion. Bracket toward Pairs 1 and 2."}, "bath": {"pair_answers": [7000, 7200], "concluded_range": [7000, 7200], "rationale": "Two pairs produce $7,000 and $7,200 — a tight bracket for the half-bath increment between 2.5 and 3 full baths."}, "date": {"pair_answers": [0.378, 0.300, 0.352], "concluded_range": [0.32, 0.37], "rationale": "Three resale pairs produce monthly appreciation rates of 0.30%, 0.35%, and 0.38%. The midpoint range of approximately 0.32–0.37%/mo represents typical appreciation for the local market over the relevant period."}}, "cost": {"gla": {"answer": 57.36, "rationale": "$80.00 × (1 − 0.283) = $57.36/SF. The depreciated cost sits well above paired sales evidence ($49–$50/SF), confirming cost as a ceiling here."}, "bath": {"answer": 10038, "rationale": "$14,000 × (1 − 0.283) = $10,038. Cost significantly exceeds paired sales of $7,000–$7,200 — a ceiling indication only. Weight paired sales."}}}, "step2_reconciliation": {"gla": {"range": [49.0, 53.0], "rationale": "Paired Sales support a tight range of $49–$50/SF (Pairs 1 & 2). Pair 3''s divergence to $54.67/SF is acknowledged but not heavily weighted — it likely reflects a different submarket or transaction anomaly. Cost support of $57.36/SF functions as a credible ceiling. Reconcile in the $50–$53/SF range, weighting paired sales heavily."}, "bath": {"range": [7000, 7200], "rationale": "Paired sales bracket $7,000–$7,200 — a tight, well-supported range. Cost of $10,038 is significantly higher and serves only as a ceiling. Reconcile within the paired sales bracket."}, "date": {"range": [0.32, 0.37], "rationale": "Paired sales support 0.32–0.37%/mo with reasonable consistency across three resale pairs. No cost method is applicable for market conditions adjustments — paired sales is the only support tool. Reconcile near the midpoint at approximately 0.35%/mo."}}, "step3_adjustments": {"C1": {"gla": {"direction": "negative", "amount_per_unit": -51.0, "units": 150, "computed_amount": -7650, "method": "Paired Sales Analysis", "rationale": "Comp 1 is 150 SF larger than the subject (superior). At a reconciled rate of approximately $51/SF, the GLA adjustment is approximately −$7,650. Round to nearest $50."}}, "C2": {"bath": {"direction": "negative", "amount": -7100, "method": "Paired Sales Analysis", "rationale": "Comp 2 has 3 full baths versus the subject''s 2.5 (superior). The half-bath increment derived from paired sales is approximately $7,100, the midpoint of the $7,000–$7,200 bracket."}}, "C3": {"date": {"direction": "positive", "amount": 9513, "method": "Market Conditions (Resale Pairs)", "rationale": "Comp 3 sold 9 months ago — older in an appreciating market (inferior). At a reconciled rate of 0.35%/mo: $302,000 × 9 × 0.35 ÷ 100 = $9,513. Round to nearest $50."}}}, "step4_adjusted_prices": {"C1": {"unadjusted": 328000, "adjusted": 320350}, "C2": {"unadjusted": 322500, "adjusted": 315400}, "C3": {"unadjusted": 302000, "adjusted": 311513}}, "step4_reconciliation_narrative": "Adjusted prices range from approximately $311,500 to $320,350 — a tight cluster of approximately $8,850, reflecting the consistency of the market evidence. The $318,000 contract price falls comfortably within this bracket. Comp 2 is the most similar before adjustments (single small adjustment for bathrooms) and deserves the most weight. The standard-level teaching point is the market conditions adjustment for Comp 3: even though the resale-pair derivation is independent of the GLA and bath analyses, all three converge on a value indication near $315,000–$317,000, supporting the contract price.", "tolerance_note": "Student answers are accepted within ±5% of model derived values for paired-sales calculations and within the indicated reconciliation range. Step 3 adjustments accepted within ±13% of the computed amount for GLA and market conditions, ±12% for bath."}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'adjustment_grid'
WHERE sc.code = 'M2-S4-C1'
  AND s.order_index = 2;

COMMIT;

